const today = new Date().toISOString().split('T')[0];
const input = $input.item.json;

return {
  json: {
    date: today,
    trigger_source: input.body ? 'webhook' : 'cron',
    user_id: input.user_id || '',
    webhook_data: input.body || null
  }
};

const today = new Date().toISOString().split('T')[0];
const triggerData = $('Merge Trigger Sources').item.json;
const themesRaw = $input.item.json;
const themes = Array.isArray(themesRaw) ? themesRaw : [themesRaw];

// Flatten weekly themes into daily content items
const dailyItems = [];
for (const theme of themes) {
  if (!theme.content_types || !Array.isArray(theme.content_types)) continue;
  for (const ct of theme.content_types) {
    dailyItems.push({
      ...ct,
      theme_id: theme.id,
      campaign_id: theme.campaign_id,
      user_id: triggerData.user_id,
      weekly_show_name: theme.theme_name || theme.show_concept || '',
      week_number: theme.week_number
    });
  }
}

// Filter to today's content if trigger is cron, otherwise use webhook body
let filteredItems = dailyItems;
if (triggerData.trigger_source === 'cron') {
  filteredItems = dailyItems.filter(item => item.date === today);
}

if (filteredItems.length === 0) {
  filteredItems = dailyItems.length > 0
    ? [dailyItems[0]]
    : [{ theme: 'General engagement post', content_type: 'Value', platform: 'LinkedIn', user_id: triggerData.user_id }];
}

return filteredItems.map(item => ({ json: item }));

// PIPE-07 FIX: Normalize content_type BEFORE the Switch node
// Claude generates: Hook, Value, Proof, Carousel, Video, Engagement, Cliffhanger
// Normalize to: text, image, video, carousel
const item = $input.item.json;
const ct = (item.content_type || '').toLowerCase().trim();

item.original_content_type = item.content_type;

if (ct.includes('video') || ct.includes('reel')) {
  item.content_type = 'video';
} else if (ct.includes('carousel') || ct.includes('thread')) {
  item.content_type = 'carousel';
} else if (ct.includes('image')) {
  item.content_type = 'image';
} else {
  item.content_type = 'text';
}

return { json: item };

