// Merge all content from text/image/video/carousel branches
const item = $input.item.json;
let content = '';
let contentType = 'text';

try {
  if (item.content && item.content[0]) {
    content = item.content[0].text;
  } else if (item.data && item.data.taskId) {
    content = JSON.stringify(item);
    contentType = 'image';
  } else {
    content = JSON.stringify(item);
  }
} catch(e) {
  content = JSON.stringify(item);
}

// Get the original data from before the Switch
const normalizeData = $('Normalize Content Type').item.json;

return {
  json: {
    user_id: normalizeData.user_id || '',
    campaign_id: normalizeData.campaign_id || null,
    theme_id: normalizeData.theme_id || null,
    title: normalizeData.theme || normalizeData.weekly_show_name || 'Generated Content',
    content: content,
    content_type: normalizeData.content_type || 'text',
    platform: (normalizeData.platform || 'linkedin').toLowerCase(),
    scheduled_date: normalizeData.date || null,
    status: 'pending_review',
    image_url: null,
    video_url: null,
    image_prompt: normalizeData.theme || ''
  }
};

// Fallback handler for unmatched content types
const item = $input.item.json;
return {
  json: {
    user_id: item.user_id || '',
    campaign_id: item.campaign_id || null,
    theme_id: item.theme_id || null,
    title: item.theme || 'Fallback Content',
    content: JSON.stringify({ note: 'Content type not matched by Switch', original_type: item.original_content_type, normalized_type: item.content_type }),
    content_type: item.content_type || 'text',
    platform: (item.platform || 'linkedin').toLowerCase(),
    scheduled_date: item.date || null,
    status: 'pending_review',
    image_url: null,
    video_url: null,
    image_prompt: ''
  }
};
